code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let a;
readline.on('line', line => {
    if (i == 0) {
        n = parseInt(line);
        i++;
    } else {
        a = line.split(' ').map(num => parseInt(num));
        let count = 0;
        for (let j = 0; j < n; j++) {
            let sum = 0;
            for (let k = j; k < n; k++) {
                sum += a[k];
                if (sum % 2 == 0) {
                    count++;
                }
            }
        }
        console.log(count);
        readline.close();
    }
});
